    FOR v_item IN SELECT * FROM jsonb_array_elements(v_json_data)
    LOOP
        v_investor_name := v_item->>'investor';
        
        -- Try to clean name for better matching (simple trim)
        -- In a real scenario, we might need fuzzy matching, but here we use strict ILIKE
        v_clean_name := trim(v_investor_name);

        -- 1. FIND OR CREATE INVESTOR
        SELECT id INTO v_investor_id FROM public.investors WHERE name ILIKE v_clean_name LIMIT 1;

        IF v_investor_id IS NULL THEN
            -- Try matching by a substring if it's a long name (like the Trust one)
            -- This is risky, so let's stick to exact-ish match or create new.
            -- Creating a new investor without an email is allowed if we generate a placeholder.
            
            INSERT INTO public.investors (name, email, status, entity_type, created_at, updated_at)
            VALUES (
                v_clean_name, 
                -- Generate placeholder email: firstname.lastname.hash@placeholder.indigo.com
                lower(regexp_replace(left(v_clean_name, 20), 'W+', '.', 'g')) || '.' || substring(md5(random()::text) from 1 for 4) || '@placeholder.indigo.com',
                'active',
                'individual', -- Default, admin can change later
                NOW(),
                NOW()
            )
            RETURNING id INTO v_investor_id;
            
            RAISE NOTICE 'Created NEW Investor: % (ID: %)', v_clean_name, v_investor_id;
        ELSE
            RAISE NOTICE 'Found Existing Investor: % (ID: %)', v_clean_name, v_investor_id;
        END IF;

        -- 2. PROCESS FUNDS
        FOR v_fund_item IN SELECT * FROM jsonb_array_elements(v_item->'funds')
        LOOP
            v_fund_name := v_fund_item->>'fund';
            
            -- Parse balance, handle "-" as 0
            IF (v_fund_item->>'balance') = '-' THEN
                v_balance := 0;
            ELSE
                v_balance := (v_fund_item->>'balance')::NUMERIC;
            END IF;

            -- Map Fund Name to Asset Symbol
            CASE v_fund_name
                WHEN 'BTC YIELD FUND' THEN v_asset_symbol := 'BTC';
                WHEN 'ETH YIELD FUND' THEN v_asset_symbol := 'ETH';
                WHEN 'SOL YIELD FUND' THEN v_asset_symbol := 'SOL';
                WHEN 'USDT YIELD FUND' THEN v_asset_symbol := 'USDT';
                WHEN 'XRP YIELD FUND' THEN v_asset_symbol := 'XRP';
                ELSE v_asset_symbol := NULL;
            END CASE;

            IF v_asset_symbol IS NOT NULL THEN
                -- Find Fund ID
                SELECT id INTO v_fund_id FROM public.funds WHERE asset_symbol = v_asset_symbol LIMIT 1;

                IF v_fund_id IS NOT NULL THEN
                    -- 3. UPSERT POSITION
                    -- We use ON CONFLICT to update if exists
                    INSERT INTO public.investor_positions (
                        investor_id, 
                        fund_id, 
                        shares, -- Assuming balance IS shares for crypto/tokens usually, or value? 
                                -- Report says "Ending Balance" (USDT/BTC/etc). 
                                -- For Yield Funds, typically Shares = Balance if NAV=1, or it tracks underlying amount.
                                -- We will set both 'shares' and 'current_value' to this amount for now, 
                                -- assuming 1:1 tracking or direct asset holding view.
                        current_value,
                        cost_basis, -- We don't know cost basis from report, preserving existing or setting to current
                        updated_at
                    )
                    VALUES (
                        v_investor_id,
                        v_fund_id,
                        v_balance,
                        v_balance, -- approximate current value
                        v_balance, -- approximate cost basis (since we don't have history here)
                        NOW()
                    )
                    ON CONFLICT (investor_id, fund_id) 
                    DO UPDATE SET
                        shares = EXCLUDED.shares,
                        current_value = EXCLUDED.current_value,
                        updated_at = NOW();
                        -- We do NOT update cost_basis on conflict to preserve history if it exists
                        
                    RAISE NOTICE 'Updated Position: % - % : %', v_clean_name, v_asset_symbol, v_balance;
                ELSE
                    RAISE WARNING 'Fund NOT Found for symbol: %', v_asset_symbol;
                END IF;
            END IF;
        END LOOP;
    END LOOP;
